if (!localStorage.getItem("images")) {
  localStorage.setItem("images", JSON.stringify(defaultImages));
}

function reimportSampleImages() {
  const overwriteCheck = document.getElementById("reimportOverwriteCheck");
  overwriteCheck.checked = false;
  const modal = new bootstrap.Modal(document.getElementById("reimportConfirmModal"));
  document.getElementById("reimportConfirmBtn").onclick = function() {
    const overwrite = overwriteCheck.checked;
    modal.hide();
    doReimport(overwrite);
  };
  modal.show();
}

function doReimport(overwrite) {
  const existing = JSON.parse(localStorage.getItem("images") || "[]");
  const existingNames = new Set(existing.map(i => i.name));
  let added = 0;
  let replaced = 0;
  defaultImages.forEach(img => {
    if (existingNames.has(img.name)) {
      if (overwrite) {
        const idx = existing.findIndex(i => i.name === img.name);
        if (idx >= 0) {
          existing[idx] = JSON.parse(JSON.stringify(img));
          replaced++;
        }
      }
    } else {
      existing.push(JSON.parse(JSON.stringify(img)));
      added++;
    }
  });
  localStorage.setItem("images", JSON.stringify(existing));
  const msg = document.getElementById("deleteConfirmMessage");
  let text = "";
  if (added > 0) text += `Added ${added} sample image${added === 1 ? '' : 's'}. `;
  if (replaced > 0) text += `Replaced ${replaced} sample image${replaced === 1 ? '' : 's'}. `;
  if (!added && !replaced) text = "All sample images already exist.";
  msg.innerHTML = text.trim();
  document.getElementById("deleteConfirmBtn").textContent = "OK";
  document.getElementById("deleteConfirmBtn").className = "btn btn-primary editor-btn btn-wide";
  document.getElementById("deleteConfirmBtn").onclick = function() {
    bootstrap.Modal.getInstance(document.getElementById("deleteConfirmModal")).hide();
    document.getElementById("deleteConfirmBtn").textContent = "Delete";
    document.getElementById("deleteConfirmBtn").className = "btn btn-danger editor-btn btn-wide";
  };
  new bootstrap.Modal(document.getElementById("deleteConfirmModal")).show();
}

